package com.pawura.model;

import com.pawura.contract.Displayable;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

/**
 * Prediction – a movement prediction generated by PredictionService.
 * Implements Displayable (POLYMORPHISM).
 */
public class Prediction implements Displayable {

    private static final DateTimeFormatter FMT =
        DateTimeFormatter.ofPattern("dd MMM yyyy  HH:mm");

    public enum ConfidenceLevel { LOW, MODERATE, HIGH, VERY_HIGH }

    private int            id;
    private Location       predictedLocation;
    private LocalDateTime  predictedAt;
    private LocalDateTime  expectedArrival;
    private double         confidenceScore;   // 0.0 – 1.0
    private ConfidenceLevel confidenceLevel;
    private String         algorithm;
    private String         notes;

    // ── Constructors ──────────────────────────────────────────────────────────
    public Prediction() { this.predictedAt = LocalDateTime.now(); }

    public Prediction(Location predictedLocation, double confidenceScore,
                      LocalDateTime expectedArrival, String algorithm) {
        this();
        this.predictedLocation = predictedLocation;
        setConfidenceScore(confidenceScore);
        this.expectedArrival   = expectedArrival;
        this.algorithm         = algorithm;
    }

    // ── Displayable (Polymorphism) ────────────────────────────────────────────
    @Override
    public String getDisplaySummary() {
        return String.format("📍 Predicted: %s  (%s confidence)",
            predictedLocation != null ? predictedLocation.getName() : "Unknown",
            confidenceLevel);
    }

    @Override
    public String getDetailText() {
        return String.format("""
            Prediction ID     : %d
            Predicted Location: %s
            Confidence Score  : %.0f%%  [%s]
            Algorithm Used    : %s
            Generated At      : %s
            Expected Arrival  : %s
            Notes             : %s
            """,
            id,
            predictedLocation != null ? predictedLocation.toString() : "—",
            confidenceScore * 100,
            confidenceLevel,
            algorithm != null ? algorithm : "—",
            predictedAt.format(FMT),
            expectedArrival != null ? expectedArrival.format(FMT) : "Unknown",
            notes != null ? notes : "—");
    }

    // ── Getters / Setters ─────────────────────────────────────────────────────
    public int             getId()                          { return id; }
    public void            setId(int id)                    { this.id = id; }
    public Location        getPredictedLocation()           { return predictedLocation; }
    public void            setPredictedLocation(Location l) { this.predictedLocation = l; }
    public LocalDateTime   getPredictedAt()                 { return predictedAt; }
    public void            setPredictedAt(LocalDateTime t)  { this.predictedAt = t; }
    public LocalDateTime   getExpectedArrival()             { return expectedArrival; }
    public void            setExpectedArrival(LocalDateTime t){ this.expectedArrival = t; }
    public double          getConfidenceScore()             { return confidenceScore; }
    public void            setConfidenceScore(double s) {
        if (s < 0 || s > 1) throw new IllegalArgumentException("Score must be 0.0–1.0");
        this.confidenceScore = s;
        this.confidenceLevel = s >= 0.75 ? ConfidenceLevel.VERY_HIGH
                             : s >= 0.55 ? ConfidenceLevel.HIGH
                             : s >= 0.35 ? ConfidenceLevel.MODERATE
                             : ConfidenceLevel.LOW;
    }
    public ConfidenceLevel getConfidenceLevel()             { return confidenceLevel; }
    public String          getAlgorithm()                   { return algorithm; }
    public void            setAlgorithm(String a)           { this.algorithm = a; }
    public String          getNotes()                       { return notes; }
    public void            setNotes(String n)               { this.notes = n; }
}
